// // This module implements a 4-bit comparator that compares two 4-bit inputs, a and b. If a is less than b, it outputs a result of 3'b100; if a is greater than b, it outputs 3'b001. If both inputs are equal, it retains the prior result provided by the pre_result input.
module top_module(a,b,pre_result,result);input [3:0] a;
    input [3:0] b;
    input [2:0] pre_result;
    output [2:0] result;

    reg [2:0]result_reg;
    assign result=result_reg;

    always @ (a or b or pre_result) begin
        if(a>b) result_reg=3'b100;
        else if(a<b) result_reg=3'b001;
        else result_reg=pre_result;
    end

endmodule
